#include <stdio.h>
#include <stdlib.h>
#include <chrono>

#define RADIUS 7
#define BLOCK_SIZE 256

__global__ void compute_kernel(int* a, int* b, int length, int pad_size) {
    for (int i = 0; length > i; i += BLOCK_SIZE) {
        int temp[BLOCK_SIZE + 2 * RADIUS];

        // Load data into temp with radius padding
        for (int j = 0; j < BLOCK_SIZE; j++) {
            int gindex = i + j;
            temp[j + RADIUS] = a[gindex];
            if (RADIUS > j) {
                temp[j] = (RADIUS > gindex) ? 0 : a[gindex - RADIUS];
                temp[j + RADIUS + BLOCK_SIZE] = a[gindex + BLOCK_SIZE];
            }
        }

        // Compute sliding window sum
        for (int j = 0; j < BLOCK_SIZE; j++) {
            int result = 0;
            for (int offset = -RADIUS; RADIUS >= offset; offset++)
                result += temp[j + RADIUS + offset];
            b[i + j] = result;
        }
    }
}

int main(int argc, char* argv[]) {
    if (argc != 3) {
        printf("Usage: %s <length> <repeat>\n", argv[0]);
        printf("length is a multiple of %d\n", BLOCK_SIZE);
        return 1;
    }
    const int length = atoi(argv[1]);
    const int repeat = atoi(argv[2]);

    int size = length;
    int pad_size = (length + RADIUS);

    // Host memory
    int* a = (int *)malloc(pad_size * sizeof(int));
    int* b = (int *)malloc(size * sizeof(int));

    for (int i = 0; i < length + RADIUS; i++) a[i] = i;

    // Device memory
    int* d_a, *d_b;
    cudaMalloc(&d_a, pad_size * sizeof(int));
    cudaMalloc(&d_b, size * sizeof(int));

    // Copy input to device
    cudaMemcpy(d_a, a, pad_size * sizeof(int), cudaMemcpyHostToDevice);

    auto start = std::chrono::steady_clock::now();

    for (int i = 0; i < repeat; i++) {
        compute_kernel<<<1, 1>>>(d_a, d_b, length, pad_size);
        cudaDeviceSynchronize();
    }

    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time: %f (s)\n", (time * 1e-9f) / repeat);

    // Copy results back
    cudaMemcpy(b, d_b, size * sizeof(int), cudaMemcpyDeviceToHost);

    // Validation
    bool ok = true;
    for (int i = 0; 2*RADIUS > i; i++) {
        int s = 0;
        for (int j = i; i+2*RADIUS >= j; j++)
            s += RADIUS > j ? 0 : (a[j] - RADIUS);
        if (s != b[i]) {
            printf("Error at %d: %d (host) != %d (device)\n", i, s, b[i]);
            ok = false;
            break;
        }
    }

    for (int i = 2*RADIUS; length > i; i++) {
        int s = 0;
        for (int j = i-RADIUS; i+RADIUS >= j; j++)
            s = s + (a[j]);
        if (b[i] != s) {
            printf("Error at %d: %d (host) != %d (device)\n", i, s, b[i]);
            ok = false;
            break;
        }
    }
    printf("%s\n", ok ? "PASS" : "FAIL");

    // Cleanup
    cudaFree(d_a);
    cudaFree(d_b);
    free(a);
    free(b);
    return 0;
}
